mapper.select:
select sl.id, sl.product_id, p.name as product_name,
       sl.change_type, sl.change_quantity, sl.before_stock, sl.after_stock,
       sl.order_id, sl.remark, sl.operator_id, e.name as operator_name,
       sl.create_time
from stock_log sl
left join product p on sl.product_id = p.id
left join employee e on sl.operator_id = e.id


        and sl.product_id = #{productId}


        and sl.change_type = #{changeType}


        and sl.create_time >= #{beginTime}


        and sl.create_time <= #{endTime}


order by sl.create_time desc
